public class Main {
    public static int countEvens(int[] arr) {
        int count = 0;
        for (int num : arr) {
            if (num % 2 == 0) {
                count++;
            }
        }
        return count;
    }

    public static void main(String[] args) {
        int[] nums = {3, 8, 12, 5, 7, 20, 1, 4};
        System.out.println(countEvens(nums));
    }
}

