            if (arr[i] == target) {
                return i;
            }
        }
        return -1;
    }

    public static void main(String[] args) {
        int[] nums = {10, 20, 30, 40, 50};
        System.out.println(linearSearch(nums, 30));
        System.out.println(linearSearch(nums, 99));
